const processClaim = (step: Step, steps: Step[]): unknown => {
  const policyItems = steps[step.policy!].items ?? [];
  const payoutCap = insuranceSumFor(policyItems) * CAP_MULTIPLIER;
  const damage = step.incident!.damages[0];
  const damagedItem = policyItems.find((item) => item.type === damage.itemType);
  const reimbursementRate =
    (damagedItem?.enchantment ?? 0) >= HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD
      ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
      : 1;
  const payout = damage.amount * reimbursementRate - DEDUCTIBLE;
  return { payout, remainingCap: payoutCap - payout };
};

const DEDUCTIBLE = 100;
const HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
